DROP VIEW IF EXISTS vCantidadProductos;
CREATE VIEW vCantidadProductos (idOrden, Fecha, Cliente, Total)
AS 
	SELECT o.idOrden, DATE(o.fCreacion), CONCAT(c.apellidos, ", ", c.nombres), SUM(d.cantidad)
    FROM Ordenes o
    INNER JOIN Clientes c ON o.idCliente = c.idCliente
    INNER JOIN Detalle d ON o.idOrden = d.idOrden
    GROUP BY idOrden, DATE(o.fCreacion), CONCAT(c.apellidos, ", ", c.nombres)
    ORDER BY 2;


