DROP PROCEDURE IF EXISTS spAltaEnvio;
DELIMITER //
CREATE PROCEDURE spAltaEnvio
(pID VARCHAR(40), pInstrucciones VARCHAR(200), pFecha DATE, pIDOrden VARCHAR(40), pfEntregaDesde DATE, pfEntregaHasta DATE, pObservs VARCHAR(200), pNumCupon VARCHAR(32), pIDTipoGrupo INT, OUT mensaje VARCHAR(100))
SALIR: BEGIN  
	IF (pID IS NULL OR pID = '') THEN
		SET mensaje = 'Error ningun campo puede ser nulo';
        LEAVE SALIR;
	END IF;
    IF (SELECT idEnvio FROM Envios WHERE idEnvio = pID) IS NOT NULL THEN
		SET mensaje = 'Id invalido';
        LEAVE SALIR;
	END IF;
    IF (pfEntregaHasta < pfEntregaDesde) THEN
		SET mensaje = 'Fechas invalidas';
        LEAVE SALIR;
	END IF;
    
    
	SET mensaje = 'Producto creado con éxito';
    
END //
DELIMITER ;


DROP PROCEDURE IF EXISTS spConsultaEnvio;
DELIMITER //
CREATE PROCEDURE spConsultaEnvio(pIdOrden VARCHAR(40), OUT mensaje VARCHAR(100))
SALIR: BEGIN  
	IF (pIdOrden IS NULL OR pIdOrden = '') THEN
		SET mensaje = 'Error id invalido';
        LEAVE SALIR;
	END IF;
    
	SELECT o.idOrden, tg.descripcion, s.idSeguimiento, est.descripcion, s.fecha
    FROM Ordenes o
    INNER JOIN Envios e 	  ON o.idOrden = e.idOrden
    INNER JOIN TiposGrupos tg ON e.idTipoGrupo = tg.idTipoGrupo
    LEFT JOIN  Seguimientos s ON e.idEnvio = s.idEnvio
    LEFT JOIN  Estados est    ON s.idEstado = est.idEstado
    WHERE o.idOrden = pIdOrden
    GROUP BY o.idOrden, tg.descripcion, s.idSeguimiento, est.descripcion, s.fecha;
    
	SET mensaje = 'OK';
    
END //
DELIMITER ;